export default function CartDrawer({ cart, setCart, open, setOpen }) {
  const total = cart.reduce((sum, item) => sum + item.price * item.qty, 0);

  function updateQty(index, delta) {
    setCart((currentCart) => {
      const nextCart = [...currentCart];
      nextCart[index] = { ...nextCart[index], qty: nextCart[index].qty + delta };
      if (nextCart[index].qty <= 0) nextCart.splice(index, 1);
      return nextCart;
    });
  }

  return (
    <>
      {open && <div className="drawer-overlay" onClick={() => setOpen(false)} />}
      <div className={`cart-drawer ${open ? "open" : ""}`}>
        <div className="drawer-header">
          <h2>
            Cart {cart.length > 0 && <span className="cart-count-badge">{cart.reduce((sum, item) => sum + item.qty, 0)}</span>}
          </h2>
          <button onClick={() => setOpen(false)}>✕</button>
        </div>
        {cart.length === 0 ? (
          <div className="empty-cart">
            <p>Your cart is empty.</p>
            <p>Add some pieces from the shop.</p>
          </div>
        ) : (
          <>
            <div className="cart-items">
              {cart.map((item, index) => (
                <div key={`${item.id}-${item.selectedSize}`} className="cart-item">
                  <div className="ci-img" style={{ background: item.color }}>
                    <img className="product-image" src={item.image} alt={item.name} />
                  </div>
                  <div className="ci-info">
                    <p className="ci-name">{item.name}</p>
                    <p className="ci-size">Size: {item.selectedSize}</p>
                    <p className="ci-price">₹{item.price.toLocaleString()}</p>
                    <div className="ci-qty">
                      <button onClick={() => updateQty(index, -1)}>−</button>
                      <span>{item.qty}</span>
                      <button onClick={() => updateQty(index, 1)}>+</button>
                    </div>
                  </div>
                </div>
              ))}
            </div>
            <div className="cart-footer">
              <div className="cart-total">
                <span>Estimated Total</span>
                <span>₹{total.toLocaleString()}</span>
              </div>
              <p className="tax-note">Duties and taxes included. Shipping calculated at checkout.</p>
              <button className="btn-primary checkout-btn">Check Out</button>
            </div>
          </>
        )}
      </div>
    </>
  );
}
